import { Component, Element, Event, EventEmitter, h, Prop, Watch } from '@stencil/core';
import { CalendarMode, CalendarSize } from '../wdpr-calendar.model';
import { startOfMonth } from '../../../utils/date.utils';
import { twMerge } from '../../../utils/utils';

@Component({
  tag: 'wdpr-swipe-calendar',
  shadow: true,
  styles: ':host { width: 100%; }',
})
export class WdprSwipeCalendar {
  @Element() el: HTMLElement;

  @Prop() selectedDate: Date | null = null;
  @Prop() startDate: Date | null = null;
  @Prop() endDate: Date | null = null;
  @Prop() hoverDate: Date | null = null;
  @Prop() mode: CalendarMode = 'single';
  @Prop() enableSixWeeks: boolean = false;
  @Prop() format: string = 'MM/dd/yyyy';
  @Prop() displayBorder: boolean = true;
  @Prop() maxRangeDate: Date | null = null;
  @Prop() minDate: Date | null = null;
  @Prop() maxDate: Date | null = null;
  @Prop() focusDate: Date | null = null;
  @Prop() isReadOnly: boolean = false;
  @Prop() displayDate: Date = new Date();
  @Prop() extras: Map<string, HTMLElement> = new Map();

  @Prop({ reflect: true }) showDisabledSlash: boolean = false;
  @Prop({ reflect: true }) size: CalendarSize = 'medium';

  @Prop() isDateBlocked?: (date: Date) => boolean;
  @Prop() isDateDot?: (date: Date) => boolean;
  @Prop() getDatePrice?: (date: Date | string) => number | undefined;

  @Event({ eventName: 'dateSelected' }) dateSelected: EventEmitter<{ date: string }>;
  @Event({ eventName: 'dateHover' }) dateHover: EventEmitter<{ date: string }>;
  @Event() focusMoveOut: EventEmitter<{ date: string }>;

  @Watch('displayDate')
  @Watch('minDate')
  @Watch('maxDate')
  validateMonths() {
    this._getMonthsToRenderCount();
    this._scheduleHorizontalScrollToDisplayMonth();
  }

  componentDidLoad() {
    this._scheduleHorizontalScrollToDisplayMonth();
  }

  private _scheduleHorizontalScrollToDisplayMonth() {
    requestAnimationFrame(() => this._scrollDisplayMonthHorizontally());
  }

  /**
   * Smoothly scrolls the horizontal scroller to center the ".display-month-swipe" element, clamping within bounds and no-op if prerequisites are missing.
   */
  private _scrollDisplayMonthHorizontally() {
    const root = this.el?.shadowRoot || this.el;
    const target = root?.querySelector('.display-month-swipe') as HTMLElement | null;
    if (!target) return;

    const scrollbarEl = root?.querySelector('wdpr-scrollbar') as (HTMLElement & { shadowRoot?: ShadowRoot | null }) | null;
    const scroller = scrollbarEl?.shadowRoot?.querySelector('.scroll-content') as HTMLElement | null;
    if (!scroller) return;

    const maxScrollLeft = scroller.scrollWidth - scroller.clientWidth;
    if (maxScrollLeft <= 0) return;

    const scrollerRect = scroller.getBoundingClientRect();
    const targetRect = target.getBoundingClientRect();

    const deltaToTargetLeft = targetRect.left - scrollerRect.left;
    const deltaToCenter = deltaToTargetLeft + (targetRect.width / 2 - scrollerRect.width / 2);

    const nextScrollLeft = Math.max(0, Math.min(scroller.scrollLeft + deltaToCenter, maxScrollLeft));

    scroller.scrollTo({ left: nextScrollLeft, behavior: 'smooth' });
  }

  private _onDateSelected = (event: CustomEvent<{ date: string }>) => {
    event.stopPropagation();
    this.dateSelected.emit(event.detail);
  };

  private _onDateHover = (event: CustomEvent<{ date: string }>) => {
    event.stopPropagation();
    this.dateHover.emit(event.detail);
  };

  private _onFocusMoveOut = (event: CustomEvent<{ date: string }>) => {
    event.stopPropagation();
    this.focusMoveOut.emit(event.detail);
  };

  private get _commonCalendarProps() {
    return {
      mode: this.mode,
      enableSixWeeks: this.enableSixWeeks,
      startDate: this.startDate,
      endDate: this.endDate,
      hoverDate: this.hoverDate,
      focusDate: this.focusDate,
      selectedDate: this.selectedDate,
      format: this.format,
      minDate: this.minDate,
      maxDate: this.maxDate,
      extras: this.extras,
      displayBorder: this.displayBorder,
      maxRangeDate: this.maxRangeDate,
      showDisabledSlash: this.showDisabledSlash,
      size: this.size,
      isReadOnly: this.isReadOnly,
      onDateSelected: this._onDateSelected,
      onDateHover: this._onDateHover,
      onFocusMoveOut: this._onFocusMoveOut,
      isDateBlocked: this.isDateBlocked,
      isDateDot: this.isDateDot,
      getDatePrice: this.getDatePrice,
    };
  }

  private _getNextMonth(date: Date, increase: number): Date {
    // Normalize to the first day of the month to avoid overflow issues
    const baseYear = date.getFullYear();
    const baseMonth = date.getMonth();

    const totalMonths = baseYear * 12 + baseMonth + increase;
    const newYear = Math.floor(totalMonths / 12);
    const newMonth = totalMonths % 12;

    return new Date(newYear, newMonth, 1);
  }

  private _getMonthsToRenderCount() {
    const { minDate, maxDate } = this;

    if (!minDate || !maxDate) return 1;
    const startTime = minDate.getTime();
    const endTime = maxDate.getTime();
    if (isNaN(startTime) || isNaN(endTime)) return 1;

    const startTotalMonths = minDate.getFullYear() * 12 + minDate.getMonth();
    const endTotalMonths = maxDate.getFullYear() * 12 + maxDate.getMonth();

    const diff = endTotalMonths - startTotalMonths;

    return diff >= 0 ? diff + 1 : 1;
  }

  get _calendarWrapperClasses() {
    const margin = this.size === 'xsmall' ? 'gap-100' : 'gap-200';

    return twMerge('flex flex-nowrap items-start pb-200', margin);
  }

  render() {
    const months = this._getMonthsToRenderCount();
    const baseDate = startOfMonth(this.minDate ?? this.displayDate);

    // Determine which month should scroll in view based on displayDate
    const displayMonthStart = startOfMonth(this.displayDate);
    let displayOffset = displayMonthStart.getFullYear() * 12 + displayMonthStart.getMonth() - (baseDate.getFullYear() * 12 + baseDate.getMonth());
    if (displayOffset < 0) displayOffset = 0;
    if (displayOffset >= months) displayOffset = months - 1;

    return (
      <wdpr-scrollbar orientation="horizontal" class="w-full">
        <section class={this._calendarWrapperClasses} part="swipe-calendar">
          {Array(months)
            .fill(null)
            .map((_, offset) => {
              const currentMonth = this._getNextMonth(baseDate, offset);

              return (
                <wdpr-single-calendar
                  key={offset}
                  {...this._commonCalendarProps}
                  displayDate={currentMonth}
                  monthHeaderVariant="default"
                  exportparts="calendar-surface"
                  class={`${offset === displayOffset ? 'display-month-swipe' : ''} w-inherit flex-shrink-0`}
                />
              );
            })}
        </section>
      </wdpr-scrollbar>
    );
  }
}
